import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/file_transfer/state/transfer_state.dart'; import 'package:googlepro/features/file_transfer/model/transfer_file.dart'; void main() { group('TransferState', () { test('TransferLoaded filters active correctly', () { final f = TransferFile(transferId: 't1', fileName: 'a.pdf', fileSizeBytes: 1000, mimeType: 'application/pdf', direction: TransferDirection.upload, status: TransferStatus.inProgress, startedAt: DateTime.now()); final state = TransferLoaded([f]); expect(state.active.length, 1); }); test('TransferLoaded filters completed correctly', () { final f = TransferFile(transferId: 't1', fileName: 'a.pdf', fileSizeBytes: 1000, mimeType: 'application/pdf', direction: TransferDirection.upload, status: TransferStatus.completed, startedAt: DateTime.now()); final state = TransferLoaded([f]); expect(state.completed.length, 1); }); }); }